import express from 'express';
import path from 'path';
import fs from 'node:fs/promises';
import { createServer as createViteServer } from 'vite';

// Hardcoded default comments to seed the file system if it does not exist
const SEED_COMMENTS = [
  {
    id: 'seed-1',
    name: 'Sarah (Game Designer)',
    text: 'Arazm, you are incredible! A 13-year-old building custom top-down survival games with Godot is absolutely legendary. Keep pushing boundaries!',
    date: new Date(Date.now() - 3 * 24 * 60 * 60 * 1000).toLocaleString(),
    likes: 12
  },
  {
    id: 'seed-2',
    name: 'مهران (برنامه‌نویس ارشد)',
    text: 'کارت فوق‌العاده‌ست پسر! بازی بقا تو گودوت رو دیدم، برای سن ۱۳ سال این فوق‌العاده حرفه‌ای طراحی شده. دمت گرم AM 🔥',
    date: new Date(Date.now() - 2 * 24 * 60 * 60 * 1000).toLocaleString('fa-IR'),
    likes: 18
  },
  {
    id: 'seed-3',
    name: 'Alex_Dev',
    text: 'The Tkinter accurate volume calculator operates with clean python script logic. Excited to see your upcoming Android messenger app launch on GitHub!',
    date: new Date(Date.now() - 1 * 24 * 60 * 60 * 1000).toLocaleString(),
    likes: 7
  },
  {
    id: 'seed-4',
    name: 'سپهر',
    text: 'بخش بازی داخل سایتت فوق‌العاده سرگرم‌کننده بود! مکانیک شلیک خودکار به زامبی‌ها واقعا عالیه. موفق باشی پسر هوشمند.',
    date: new Date(Date.now() - 8 * 60 * 60 * 1000).toLocaleString('fa-IR'),
    likes: 15
  }
];

async function startServer() {
  const app = express();
  const PORT = 3000;
  const DATA_DIR = path.join(process.cwd(), 'data');
  const COMMENTS_FILE = path.join(DATA_DIR, 'comments.json');

  // Ensure directories and files exist for persistent storage
  try {
    await fs.mkdir(DATA_DIR, { recursive: true });
    try {
      await fs.access(COMMENTS_FILE);
    } catch {
      // File doesn't exist, create it with seed comments
      await fs.writeFile(COMMENTS_FILE, JSON.stringify(SEED_COMMENTS, null, 2), 'utf8');
      console.log('Seeded initial comments in database!');
    }
  } catch (err) {
    console.error('Error initializing comment directory:', err);
  }

  // Middleware
  app.use(express.json());

  // API 1: Get comments
  app.get('/api/comments', async (req, res) => {
    try {
      const content = await fs.readFile(COMMENTS_FILE, 'utf8');
      const comments = JSON.parse(content);
      // Sort comments by date or keep reverse chronological
      res.json(comments);
    } catch (error) {
      console.error('Failed to read comments:', error);
      res.status(500).json({ error: 'Failed to retrieve comments from database' });
    }
  });

  // API 2: Create a comment
  app.post('/api/comments', async (req, res) => {
    try {
      const { name, text } = req.body;
      if (!name || !text || String(name).trim() === '' || String(text).trim() === '') {
        return res.status(400).json({ error: 'Name and message are required' });
      }

      const content = await fs.readFile(COMMENTS_FILE, 'utf8');
      const comments = JSON.parse(content);

      const isFarsi = /[\u0600-\u06FF]/.test(text + name);
      const formattedDate = isFarsi 
        ? new Date().toLocaleString('fa-IR') 
        : new Date().toLocaleString();

      const newComment = {
        id: 'comment-' + Date.now() + '-' + Math.floor(Math.random() * 1000),
        name: String(name).slice(0, 48).trim(),
        text: String(text).slice(0, 500).trim(),
        date: formattedDate,
        likes: 0
      };

      comments.unshift(newComment); // Newest first
      await fs.writeFile(COMMENTS_FILE, JSON.stringify(comments, null, 2), 'utf8');
      res.status(201).json(newComment);
    } catch (error) {
      console.error('Failed to save comment:', error);
      res.status(500).json({ error: 'Failed to persist comment in database' });
    }
  });

  // API 3: Like a comment
  app.post('/api/comments/:id/like', async (req, res) => {
    try {
      const { id } = req.params;
      const content = await fs.readFile(COMMENTS_FILE, 'utf8');
      const comments = JSON.parse(content);

      const commentIndex = comments.findIndex((c: any) => c.id === id);
      if (commentIndex === -1) {
        return res.status(404).json({ error: 'Comment not found' });
      }

      comments[commentIndex].likes += 1;
      await fs.writeFile(COMMENTS_FILE, JSON.stringify(comments, null, 2), 'utf8');
      res.json(comments[commentIndex]);
    } catch (error) {
      console.error('Failed to update likes:', error);
      res.status(500).json({ error: 'Failed to update likes on database' });
    }
  });

  // Serve static UI or load Vite middleware in Development
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: 'spa',
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    // Serve HTML
    app.get('*', (req, res) => {
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  app.listen(PORT, '0.0.0.0', () => {
    console.log(`Express server running on http://0.0.0.0:${PORT}`);
  });
}

startServer();
